VALUES
  ('pukao-0c700c30-moex-00144', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '一家獨占廠商面對的需求線是P=100-Q，其中P和Q分別代表市場的價格與需求量。如果當這家廠商將價格 訂在60元時，它可以賺取最大利潤，此時它生產的邊際成本是多少？', '["60元", "50元", "40元", "20元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00145', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '一家自然獨占廠商面對的需求線是P=102-Q，其中P和Q分別代表市場的價格與需求量。如果當這家廠商的 邊際成本是2時，固定成本是1600。當政府採用平均成本訂價法管制這家廠商，並要求產量必須超過50單 位時，社會的無謂損失（deadweightloss）是多少？', '["200", "400", "800", "1600"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00146', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '雙占的研發賽局中，其報償如下：當A廠商與B廠商（下稱A、B）均研發時利潤分別為5萬元和3萬元；A、 B均不研發時利潤分別為15萬元和8萬元；A研發但B不研發時利潤分別為20萬元和1萬元；A不研發但B研 發時利潤分別為3萬元和12萬元。若B採取以牙還牙的策略，而A在第零期研發，則A在第一期與第二期該 如何做研發的選擇？', '["第一期研發，第二期研發", "第一期不研發，第二期研發", "第一期研發，第二期不研發", "第一期不研發，第二期不研發"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00147', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '在借貸市場中，利率是資本的價格。當政府對利息所得課稅時，對借貸市場均衡之影響，下列何者正確？', '["利息所得課稅政策會使得資本供給線左移，導致市場均衡利率提高", "利息所得課稅政策會使得資本需求線左移，導致市場均衡利率降低", "利息所得課稅政策會使得資本供給線右移，導致市場均衡利率下降", "利息所得課稅政策會使得資本需求線右移，導致市場均衡利率提高"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00148', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '對於生產要素的敘述，下列何者錯誤？', '["要素需求是一種引申需求", "廣義而言企業才能也是一種生產要素", "財貨間有替代財與互補財，但是生產要素間僅有替代沒有互補的情況", "土地資源也是一種生產要素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00149', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '當要素市場為完全競爭時，下列何者並非成本極小化的必要條件？', '["要素的邊際技術替代率（MRTS）等於要素的相對價格", "每種要素的價格皆等於其邊際生產收益（MRP）", "各種要素的邊際生產收益（MRP）皆必須相等", "MPL/w=MPK/r，其中MPL與MPK分別代表勞動與資本的邊際產出，w與r分別代表要素價格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00150', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '下列何者不是政府解決外部性的方式？', '["課稅或補貼", "賦予財產權", "直接管制", "透過市場"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00151', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '從經濟學的觀點來看，最適的污染水準應該為何？', '["污染等於零", "使得污染的社會邊際成本降至零", "使得污染的社會邊際成本等於社會邊際收益", "使得污染的社會邊際收益等於零"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00152', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '有關公共財以及私有財的敘述，下列何者錯誤？', '["私有財的市場需求曲線乃是個別需求曲線的垂直加總", "公共財的市場需求曲線乃是個別需求曲線作垂直加總", "市場達到均衡時每個消費者對私有財付出的價格均相同", "每個消費者對公共財的消費量均相同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00153', 'pukao-0c700c30', 'pukao-0c700c30-moex-112-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '在勞動力和自然失業率（naturalrateofunemployment）都維持固定之下，若負面衝擊（negativeshocks）造 成經濟的實際失業率（actualunemploymentrate）高於自然失業率的幅度出現擴大，則該經濟體的：', '["循環性、結構性與摩擦性失業（cyclical,structural,andfrictionalunemployment）均上升", "摩擦性和結構性失業都下降，但循環性失業上升", "摩擦性和結構性失業都上升，但循環性失業不變", "摩擦性和結構性失業都不變，但循環性失業上升"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3c0482ee47bc", "answer_pdf_sha1": "f0806c49c35d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "414", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL)
